    <span class="magi-nav-logo-text">MAGI</span>
  </a>
  <div class="magi-nav-scroll">`;

  for (const group of NAV_GROUPS) {
    html += `<div class="magi-nav-group-label">${group.label}</div>`;
    for (const item of group.items) {
      const isActive = activePage === item.id ? ' active' : '';
      html += `<a class="magi-nav-item${isActive}" href="${item.path}">
        <span class="magi-nav-item-icon">${item.icon}</span>
        <span class="magi-nav-item-label">${item.label}</span>
      </a>`;
    }
  }

  html += '</div>';
