  burger.addEventListener('click', toggleMobileNav);
  overlay.addEventListener('click', toggleMobileNav);

  return nav;
}

/**
 * MAGI WebSocket Manager
 * ES Module: import { WSManager } from '/shared/ws-manager.js';
 */

const DEFAULT_OPTIONS = {
  maxRetries: 20,
  heartbeatInterval: 30000,   // 30s ping
  reconnectBase: 1000,        // 1s initial
  reconnectMax: 30000,        // 30s max
};

export class WSManager {
  constructor(url, options = {}) {
    this._url = url;
    this._opts = { ...DEFAULT_OPTIONS, ...options };
    this._ws = null;
    this._listeners = {};
    this._retries = 0;
    this._heartbeatTimer = null;
    this._reconnectTimer = null;
    this._intentionalClose = false;
    this._indicator = null;
  }

  // ── Public API ──

  connect() {
    this._intentionalClose = false;
    this._doConnect();
    return this;
  }

  disconnect() {
    this._intentionalClose = true;
    this._cleanup();
    if (this._ws) {
      this._ws.close(1000, 'Client disconnect');
      this._ws = null;
    }
    this._setIndicator('offline');
  }

  send(data) {
    if (this._ws?.readyState === WebSocket.OPEN) {
      this._ws.send(typeof data === 'string' ? data : JSON.stringify(data));
      return true;
    }
    return false;
  }

  on(event, handler) {
    if (!this._listeners[event]) this._listeners[event] = [];
    this._listeners[event].push(handler);
    return this;
  }

  off(event, handler) {
    const arr = this._listeners[event];
    if (!arr) return this;
    this._listeners[event] = arr.filter(h => h !== handler);
    return this;
  }

  get state() {
    if (!this._ws) return 'disconnected';
    switch (this._ws.readyState) {
      case WebSocket.CONNECTING: return 'connecting';
      case WebSocket.OPEN: return 'connected';
      case WebSocket.CLOSING: return 'closing';
      case WebSocket.CLOSED: return 'disconnected';
      default: return 'unknown';
    }
  }

  // ── Internal ──

  _emit(event, data) {
    const arr = this._listeners[event];
    if (arr) arr.forEach(fn => { try { fn(data); } catch (e) { console.error('[WS]', e); } });
  }

  _doConnect() {
    this._cleanup();
    this._setIndicator('connecting');

    try {
      this._ws = new WebSocket(this._url);
    } catch (e) {
      this._scheduleReconnect();
      return;
    }

    this._ws.onopen = () => {
      this._retries = 0;
      this._setIndicator('connected');
      this._startHeartbeat();
      this._emit('open');
    };

    this._ws.onclose = (e) => {
      this._cleanup();
      this._setIndicator('offline');
      this._emit('close', e);
      if (!this._intentionalClose) {
        this._scheduleReconnect();
      }
    };

    this._ws.onerror = (e) => {
      this._emit('error', e);
      // onclose will fire after onerror, so reconnect logic is there
      this._ws.close();
    };

    this._ws.onmessage = (e) => {
      let data;
      try { data = JSON.parse(e.data); } catch { data = e.data; }

      // Handle server ping
      if (data?.type === 'ping') {
        this.send({ type: 'pong' });
        return;
      }

      this._emit('message', data);
    };
  }

  _scheduleReconnect() {
    if (this._intentionalClose) return;

    this._retries++;
    if (this._retries > this._opts.maxRetries) {
      this._setIndicator('offline');
      this._emit('max-retries', this._retries);
      return;
    }

    // Exponential backoff with jitter
    const delay = Math.min(
      this._opts.reconnectBase * Math.pow(2, this._retries - 1) + Math.random() * 500,
      this._opts.reconnectMax
    );

    this._setIndicator('reconnecting');
    this._emit('reconnecting', { attempt: this._retries, delay });

    this._reconnectTimer = setTimeout(() => this._doConnect(), delay);
  }

  _startHeartbeat() {
    this._stopHeartbeat();
    this._heartbeatTimer = setInterval(() => {
      if (this._ws?.readyState === WebSocket.OPEN) {
        this.send({ type: 'ping' });
      }
    }, this._opts.heartbeatInterval);
  }

  _stopHeartbeat() {
    if (this._heartbeatTimer) {
      clearInterval(this._heartbeatTimer);
      this._heartbeatTimer = null;
    }
  }

  _cleanup() {
    this._stopHeartbeat();
    if (this._reconnectTimer) {
      clearTimeout(this._reconnectTimer);
      this._reconnectTimer = null;
    }
  }

  // ── Visual Indicator ──

  _setIndicator(state) {
    // state: 'connected' | 'connecting' | 'reconnecting' | 'offline'
    if (!this._indicator) {
      this._indicator = document.getElementById('ws-indicator');
    }
    if (!this._indicator) return;

    const dot = this._indicator.querySelector('.ws-dot') || this._indicator;

    dot.classList.remove('ws-connected', 'ws-connecting', 'ws-reconnecting', 'ws-offline');
    dot.classList.add(`ws-${state}`);

    const label = this._indicator.querySelector('.ws-label');
    if (label) {
      const labels = {
        connected: 'Online',
        connecting: 'Connecting',
        reconnecting: 'Reconnecting',
        offline: 'Offline'
      };
      label.textContent = labels[state] || state;
    }
  }
}

